// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  order: OrderStore
  orderItem: OrderItemStore
  waitlistEntry: WaitlistEntryStore
  siteContent: SiteContentStore
  review: ReviewStore
  productOverride: ProductOverrideStore
  newsletterSubscriber: NewsletterSubscriberStore
  emailLog: EmailLogStore

  constructor() {
    this.user = new UserStore()
    this.order = new OrderStore()
    this.orderItem = new OrderItemStore()
    this.waitlistEntry = new WaitlistEntryStore()
    this.siteContent = new SiteContentStore()
    this.review = new ReviewStore()
    this.productOverride = new ProductOverrideStore()
    this.newsletterSubscriber = new NewsletterSubscriberStore()
    this.emailLog = new EmailLogStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.order.clear()
    this.orderItem.clear()
    this.waitlistEntry.clear()
    this.siteContent.clear()
    this.review.clear()
    this.productOverride.clear()
    this.newsletterSubscriber.clear()
    this.emailLog.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
